UPDATE steering
SET status = #{targetStatus}, lock_version = lock_version + 1, updated_at = NOW()
WHERE id = #{id} AND status = #{expectedStatus}

mapper.select:
SELECT id, title, content, category_id, status, current_version, tags, keywords, author,
       lock_version, created_by, updated_by, created_at, updated_at, deleted
FROM steering
WHERE deleted = false
AND status = #{status}
AND category_id = #{categoryId}

    AND (title LIKE CONCAT('%', #{keyword}, '%') OR tags LIKE CONCAT('%', #{keyword}, '%') OR keywords LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY updated_at DESC
LIMIT #{size} OFFSET #{offset}

